  ('about_learn_discovery_desc', 'en', 'Search, age filters, and source filters such as favorites, mine, and public library help you find the right content quickly.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'id', 'Pencarian, filter usia, dan filter sumber seperti favorit, milik saya, dan perpustakaan umum membantu Anda menemukan konten yang tepat dengan cepat.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'bg', 'Търсене, филтри за възраст и филтри за източници като любими, моя и обществена библиотека ви помагат бързо да намерите правилното съдържание.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'cs', 'Vyhledávání, věkové filtry a zdrojové filtry, jako jsou oblíbené, moje a veřejné knihovny, vám pomohou rychle najít správný obsah.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'da', 'Søgning, aldersfiltre og kildefiltre såsom favoritter, mine og offentlige biblioteker hjælper dig med at finde det rigtige indhold hurtigt.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'de', 'Mithilfe von Suchfunktionen, Altersfiltern und Quellfiltern wie „Favoriten“, „Meine Dateien“ und „Öffentliche Bibliothek“ finden Sie schnell die richtigen Inhalte.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'et', 'Otsingu-, vanusefiltrid ja allikafiltrid, nagu lemmikud, minu oma ja avalik kogu, aitavad teil õige sisu kiiresti leida.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'es', 'Los filtros de búsqueda, edad y fuentes, como favoritos, míos y de biblioteca pública, le ayudan a encontrar el contenido adecuado rápidamente.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'fr', 'La recherche, les filtres d''âge et les filtres de source tels que les favoris, le mien et la bibliothèque publique vous aident à trouver rapidement le bon contenu.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'ga', 'Cuidíonn cuardaigh, scagairí aoise, agus scagairí foinse amhail ceanáin, mo chuid féin agus leabharlann poiblí leat an t-inneachar ceart a aimsiú go tapa.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'hr', 'Pretraživanje, filtri za dob i filtri izvora kao što su favoriti, moje i javna biblioteka pomažu vam da brzo pronađete pravi sadržaj.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'it', 'La ricerca, i filtri per età e i filtri di origine come Preferiti, Mio e Biblioteca pubblica ti aiutano a trovare rapidamente il contenuto giusto.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'lv', 'Meklēšana, vecuma filtri un avotu filtri, piemēram, izlases, mana un publiskā bibliotēka, palīdz ātri atrast pareizo saturu.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'lt', 'Paieška, amžiaus filtrai ir šaltinio filtrai, pvz., mėgstamiausiųjų, mano ir viešosios bibliotekos, padeda greitai rasti reikiamą turinį.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'hu', 'A keresés, az életkor szűrői és a forrásszűrők, például a kedvencek, az enyém és a nyilvános könyvtár segít gyorsan megtalálni a megfelelő tartalmat.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'mt', 'It-tfittxija, il-filtri tal-età, u l-filtri tas-sors bħal favoriti, tiegħi, u librerija pubblika jgħinuk issib il-kontenut it-tajjeb malajr.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'nl', 'Zoek-, leeftijds- en bronfilters zoals favorieten, mijn en openbare bibliotheek helpen je snel de juiste inhoud te vinden.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'pl', 'Wyszukiwanie, filtry wieku i filtry źródeł, takie jak ulubione, moje i biblioteki publiczne, pomagają szybko znaleźć odpowiednią treść.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'pt', 'Pesquisa, filtros de idade e filtros de origem, como favoritos, meus e biblioteca pública, ajudam você a encontrar o conteúdo certo rapidamente.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'ro', 'Căutarea, filtrele de vârstă și filtrele sursă, cum ar fi favorite, ale mele și biblioteca publică, vă ajută să găsiți rapid conținutul potrivit.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'sk', 'Vyhľadávanie, filtre podľa veku a filtre zdrojov, ako sú obľúbené, moje a verejné knižnice, vám pomôžu rýchlo nájsť ten správny obsah.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'sl', 'Iskanje, starostni filtri in izvorni filtri, kot so priljubljene, moje in javna knjižnica, vam pomagajo hitro najti pravo vsebino.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'fi', 'Haku, ikäsuodattimet ja lähdesuodattimet, kuten suosikit, omani ja julkinen kirjasto, auttavat sinua löytämään oikean sisällön nopeasti.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'sv', 'Sök, åldersfilter och källfilter som favoriter, mitt och offentliga bibliotek hjälper dig att snabbt hitta rätt innehåll.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'tl', 'Ang paghahanap, mga filter ng edad, at mga filter ng pinagmulan gaya ng mga paborito, minahan, at pampublikong aklatan ay tumutulong sa iyong mahanap ang tamang nilalaman nang mabilis.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'vi', 'Tìm kiếm, bộ lọc độ tuổi và bộ lọc nguồn như mục yêu thích, của tôi và thư viện công cộng giúp bạn nhanh chóng tìm thấy nội dung phù hợp.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'tr', 'Arama, yaş filtreleri ve favoriler, benimki ve halk kütüphanesi gibi kaynak filtreleri, doğru içeriği hızlı bir şekilde bulmanıza yardımcı olur.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'el', 'Η αναζήτηση, τα φίλτρα ηλικίας και τα φίλτρα πηγής, όπως τα αγαπημένα, η δική μου και η δημόσια βιβλιοθήκη σάς βοηθούν να βρείτε γρήγορα το σωστό περιεχόμενο.', CURRENT_TIMESTAMP)
INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('about_learn_discovery_desc', 'uk', 'Пошук, вікові фільтри та фільтри джерел, як-от вибране, моє та загальнодоступна бібліотека, допоможуть швидко знайти потрібний вміст.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'ar', 'تساعدك عوامل تصفية البحث والعمر وعوامل تصفية المصدر مثل المفضلة والمكتبة العامة في العثور على المحتوى المناسب بسرعة.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'hi', 'खोज, आयु फ़िल्टर और स्रोत फ़िल्टर जैसे पसंदीदा, मेरा और सार्वजनिक लाइब्रेरी आपको सही सामग्री शीघ्रता से ढूंढने में मदद करते हैं।', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'zh', '搜索、年龄过滤器和源过滤器（例如收藏夹、我的和公共图书馆）可帮助您快速找到合适的内容。', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'ja', '検索、年齢フィルター、お気に入り、私のもの、公共ライブラリなどのソース フィルターを使用すると、適切なコンテンツをすばやく見つけることができます。', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'ko', '검색, 연령 필터, 즐겨찾기, 내 라이브러리 등의 소스 필터를 통해 원하는 콘텐츠를 빠르게 찾을 수 있습니다.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_title', 'en', 'Discovery and Filtering', CURRENT_TIMESTAMP),
