  ('about_learn_media_title', 'el', 'Υποστήριξη πολυμέσων', CURRENT_TIMESTAMP),
  ('about_learn_media_title', 'uk', 'Підтримка ЗМІ', CURRENT_TIMESTAMP),
  ('about_learn_media_title', 'ar', 'دعم وسائل الإعلام', CURRENT_TIMESTAMP),
  ('about_learn_media_title', 'hi', 'मीडिया समर्थन', CURRENT_TIMESTAMP),
  ('about_learn_media_title', 'zh', '媒体支持', CURRENT_TIMESTAMP),
  ('about_learn_media_title', 'ja', 'メディアサポート', CURRENT_TIMESTAMP),
  ('about_learn_media_title', 'ko', '미디어 지원', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'en', 'Use Learn to build recognition and confidence, then switch to Test when you want stricter recall and faster review.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'id', 'Gunakan Pelajari untuk membangun pengakuan dan kepercayaan diri, lalu beralih ke Tes ketika Anda ingin mengingat lebih ketat dan meninjau lebih cepat.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'bg', 'Използвайте Научете, за да изградите разпознаване и увереност, след това превключете на Тест, когато искате по-стриктно извикване и по-бърз преглед.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'cs', 'Použijte funkci Naučit k budování uznání a důvěry a poté přepněte na Test, když chcete přísnější zapamatování a rychlejší kontrolu.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'da', 'Brug Lær til at opbygge genkendelse og selvtillid, og skift derefter til Test, når du ønsker en strengere tilbagekaldelse og hurtigere gennemgang.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'de', 'Verwenden Sie „Lernen“, um Anerkennung und Vertrauen aufzubauen, und wechseln Sie dann zu „Testen“, wenn Sie eine strengere Erinnerung und eine schnellere Überprüfung wünschen.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'et', 'Kasutage äratundmise ja enesekindluse suurendamiseks funktsiooni Õppimine, seejärel lülitage valikule Test, kui soovite rangemat meeldetuletust ja kiiremat ülevaatamist.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'es', 'Utilice Aprender para generar reconocimiento y confianza, luego cambie a Probar cuando desee una recuperación más estricta y una revisión más rápida.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'fr', 'Utilisez Apprendre pour renforcer la reconnaissance et la confiance, puis passez à Test lorsque vous souhaitez un rappel plus strict et une révision plus rapide.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'ga', 'Úsáid Foghlaim chun aitheantas agus muinín a thógáil, ansin aistrigh go Tástáil nuair is mian leat athghairm níos déine agus athbhreithniú níos tapúla.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'hr', 'Upotrijebite Learn kako biste izgradili prepoznavanje i samopouzdanje, a zatim se prebacite na Test kada želite strože prisjećanje i brži pregled.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'it', 'Utilizza Impara per creare riconoscimento e sicurezza, quindi passa a Test quando desideri un richiamo più rigoroso e una revisione più rapida.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'lv', 'Izmantojiet Mācīties, lai palielinātu atpazīstamību un pārliecību, pēc tam pārslēdzieties uz Testēt, ja vēlaties stingrāku atsaukšanu un ātrāku pārskatīšanu.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'lt', 'Naudokite „Mokytis“, kad sukurtumėte atpažinimą ir pasitikėjimą, tada perjunkite į „Test“, kai norite griežčiau prisiminti ir greičiau peržiūrėti.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'hu', 'Használja a Tanulás funkciót a felismerés és magabiztosság növelésére, majd váltson a Tesztre, ha szigorúbb visszahívást és gyorsabb ellenőrzést szeretne.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'mt', 'Uża Tgħallem biex tibni rikonoxximent u kunfidenza, imbagħad aqleb għal Test meta trid tirtira aktar stretta u reviżjoni aktar mgħaġġla.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'nl', 'Gebruik Learn om herkenning en vertrouwen op te bouwen en schakel vervolgens over naar Test als u striktere terugroeping en snellere beoordeling wilt.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'pl', 'Skorzystaj z opcji Naucz się, aby zyskać uznanie i pewność siebie, a następnie przełącz się na opcję Testuj, jeśli chcesz dokładniej zapamiętać dane i przyspieszyć ich sprawdzanie.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'pt', 'Use Aprender para criar reconhecimento e confiança e, em seguida, mude para Teste quando desejar uma recuperação mais rigorosa e uma revisão mais rápida.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'ro', 'Folosiți Învățați pentru a construi recunoașterea și încrederea, apoi treceți la Test când doriți o reamintire mai strictă și o examinare mai rapidă.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'sk', 'Použite funkciu Naučiť sa, aby ste získali uznanie a dôveru, a potom prepnite na Test, keď chcete prísnejšie zapamätanie a rýchlejšiu kontrolu.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'sl', 'Uporabite Naučite se, da pridobite prepoznavnost in zaupanje, nato pa preklopite na Test, ko želite strožji priklic in hitrejši pregled.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'fi', 'Käytä Learn-toimintoa tunnistuksen ja luottamuksen lisäämiseen ja vaihda sitten Testiin, kun haluat tiukempaa muistamista ja nopeampaa tarkistusta.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'sv', 'Använd Lär dig för att skapa igenkänning och självförtroende, växla sedan till Testa när du vill ha striktare återkallelse och snabbare granskning.', CURRENT_TIMESTAMP)
INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('about_learn_modes_desc', 'tl', 'Gamitin ang Alamin upang bumuo ng pagkilala at kumpiyansa, pagkatapos ay lumipat sa Pagsubok kapag gusto mo ng mas mahigpit na pag-recall at mas mabilis na pagsusuri.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'vi', 'Sử dụng Học để xây dựng sự công nhận và sự tự tin, sau đó chuyển sang Kiểm tra khi bạn muốn nhớ lại chặt chẽ hơn và ôn tập nhanh hơn.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'tr', 'Tanınırlık ve güven oluşturmak için Öğren''i kullanın, ardından daha sıkı hatırlama ve daha hızlı inceleme istediğinizde Test''e geçin.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'el', 'Χρησιμοποιήστε το Μάθετε για να χτίσετε την αναγνώριση και την αυτοπεποίθηση και, στη συνέχεια, μεταβείτε στη δοκιμή όταν θέλετε πιο αυστηρή ανάκληση και ταχύτερο έλεγχο.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'uk', 'Використовуйте «Навчання», щоб розвинути впізнаваність і впевненість, а потім перейдіть на «Тест», якщо потрібно точніше запам’ятовувати та швидше переглядати.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'ar', 'استخدم التعلم لبناء التعرف والثقة، ثم قم بالتبديل إلى الاختبار عندما تريد استدعاء أكثر صرامة ومراجعة أسرع.', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'hi', 'पहचान और आत्मविश्वास बनाने के लिए लर्न का उपयोग करें, फिर जब आप सख्त रिकॉल और तेज समीक्षा चाहते हैं तो टेस्ट पर स्विच करें।', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'zh', '使用“学习”来建立认可和信心，然后在需要更严格的回忆和更快的审查时切换到“测试”。', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'ja', '「学習」を使用して認識と自信を構築し、より厳密に思い出して迅速なレビューが必要な場合は「テスト」に切り替えます。', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'ko', '학습을 사용하여 인지도와 자신감을 쌓은 다음 더 엄격한 회상과 빠른 검토를 원할 때 테스트로 전환하세요.', CURRENT_TIMESTAMP),
