  ('about_organize_collections_desc', 'en', 'Collections combine multiple subjects into one study flow, which is useful for mixed review and curated sets.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'id', 'Koleksi menggabungkan beberapa subjek ke dalam satu alur studi, yang berguna untuk tinjauan campuran dan kumpulan yang dikurasi.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'bg', 'Колекциите комбинират множество предмети в един поток на обучение, което е полезно за смесен преглед и курирани комплекти.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'cs', 'Kolekce kombinují více předmětů do jednoho studijního toku, což je užitečné pro smíšené recenze a kurátorské sady.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'da', 'Samlinger kombinerer flere emner i ét studieflow, hvilket er nyttigt til blandede gennemgange og kuraterede sæt.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'de', 'Sammlungen kombinieren mehrere Themen in einem Studienablauf, was für gemischte Überprüfungen und kuratierte Sets nützlich ist.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'et', 'Kogud ühendavad mitu ainet üheks õppevooks, mis on kasulik segaarvustuste ja kureeritud komplektide jaoks.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'es', 'Las colecciones combinan varios temas en un solo flujo de estudio, lo que resulta útil para revisiones mixtas y conjuntos seleccionados.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'fr', 'Les collections combinent plusieurs sujets en un seul flux d''étude, ce qui est utile pour les revues mixtes et les ensembles organisés.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'ga', 'Comhcheanglaíonn bailiúcháin ábhair iolracha in aon sreabhadh staidéir amháin, atá úsáideach le haghaidh athbhreithnithe measctha agus tacair choimeádaithe.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'hr', 'Zbirke kombiniraju više predmeta u jedan tijek proučavanja, što je korisno za mješovite recenzije i odabrane skupove.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'it', 'Le raccolte combinano più argomenti in un unico flusso di studio, utile per revisioni miste e set curati.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'lv', 'Kolekcijas apvieno vairākus priekšmetus vienā studiju plūsmā, kas ir noderīga jauktām pārskatīšanām un atlasītajām kopām.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'lt', 'Kolekcijose keli dalykai sujungiami į vieną studijų srautą, o tai naudinga atliekant mišrias apžvalgas ir kuruojamus rinkinius.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'hu', 'A gyűjtemények több tárgyat egyesítenek egy tanulmányi folyamatba, ami hasznos vegyes áttekintések és válogatott készletek esetén.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'mt', 'Kollezzjonijiet jgħaqqdu suġġetti multipli fi fluss wieħed ta ''studju, li huwa utli għal reviżjoni mħallta u settijiet kkurati.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'nl', 'Collecties combineren meerdere onderwerpen in één studiestroom, wat handig is voor gemengde beoordelingen en samengestelde sets.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'pl', 'Kolekcje łączą wiele tematów w jeden proces badawczy, co jest przydatne w przypadku mieszanych recenzji i zestawów kuratorskich.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'pt', 'As coleções combinam vários assuntos em um fluxo de estudo, o que é útil para revisões mistas e conjuntos selecionados.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'ro', 'Colecțiile combină mai multe subiecte într-un singur flux de studiu, ceea ce este util pentru recenzii mixte și seturi organizate.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'sk', 'Kolekcie kombinujú viacero predmetov do jedného študijného toku, čo je užitočné pre zmiešané recenzie a vybrané súbory.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'sl', 'Zbirke združujejo več predmetov v en študijski tok, kar je uporabno za mešane preglede in kurirane sklope.', CURRENT_TIMESTAMP)
INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('about_organize_collections_desc', 'fi', 'Kokoelmat yhdistävät useita aiheita yhdeksi tutkimusvirtaukseksi, mikä on hyödyllistä sekaarvosteluissa ja kuratoiduissa sarjoissa.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'sv', 'Samlingar kombinerar flera ämnen i ett studieflöde, vilket är användbart för blandade granskningar och kurerade uppsättningar.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'tl', 'Pinagsasama ng mga koleksyon ang maraming paksa sa isang daloy ng pag-aaral, na kapaki-pakinabang para sa magkahalong pagsusuri at mga na-curate na hanay.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'vi', 'Bộ sưu tập kết hợp nhiều chủ đề vào một luồng nghiên cứu, rất hữu ích cho các học phần được tuyển chọn và đánh giá hỗn hợp.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'tr', 'Koleksiyonlar, birden fazla konuyu tek bir çalışma akışında birleştirir; bu, karma inceleme ve seçilmiş setler için faydalıdır.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'el', 'Οι συλλογές συνδυάζουν πολλά θέματα σε μια ροή μελέτης, η οποία είναι χρήσιμη για μεικτές αναθεωρήσεις και επιμελημένα σύνολα.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'uk', 'Колекції об’єднують кілька предметів в один навчальний потік, що корисно для змішаного огляду та кураторських наборів.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'ar', 'تجمع المجموعات موضوعات متعددة في مسار دراسة واحد، وهو أمر مفيد للمراجعة المختلطة والمجموعات المنسقة.', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'hi', 'संग्रह कई विषयों को एक अध्ययन प्रवाह में जोड़ते हैं, जो मिश्रित समीक्षा और क्यूरेटेड सेट के लिए उपयोगी है।', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'zh', '集合将多个主题合并到一个研究流程中，这对于混合审查和策划集很有用。', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'ja', 'コレクションは、複数の主題を 1 つの学習フローに結合します。これは、混合レビューや厳選されたセットに役立ちます。', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'ko', '컬렉션은 여러 주제를 하나의 학습 흐름으로 결합하므로 혼합 검토 및 선별된 세트에 유용합니다.', CURRENT_TIMESTAMP),
