  ('about_organize_subjects_desc', 'en', 'Subjects are the main unit of study. They hold the cards you open in Learn and Test sessions.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'id', 'Mata pelajaran merupakan unit utama pembelajaran. Mereka memegang kartu yang Anda buka di sesi Belajar dan Tes.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'bg', 'Предметите са основната учебна единица. Те държат картите, които отваряте в сесиите за обучение и тестване.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'cs', 'Předměty jsou hlavní jednotkou studia. Drží karty, které otevřete v relacích učení a testování.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'da', 'Fagene er hovedstudieenheden. De har de kort, du åbner i Lær og Test-sessioner.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'de', 'Die Fächer sind die Haupteinheit des Studiums. Sie enthalten die Karten, die Sie in Lern- und Testsitzungen öffnen.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'et', 'Õppeained on õppetöö põhiüksus. Neil on kaardid, mille avanete õppimise ja testimise seanssides.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'es', 'Las materias son la principal unidad de estudio. Contienen las tarjetas que abres en las sesiones de aprendizaje y prueba.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'fr', 'Les matières constituent la principale unité d’étude. Ils contiennent les cartes que vous ouvrez lors des sessions d''apprentissage et de test.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'ga', 'Is iad na hábhair an príomhaonad staidéir. Coinníonn siad na cártaí a osclaíonn tú i seisiúin Foghlaim agus Tástála.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'hr', 'Predmeti su glavna jedinica učenja. Oni drže kartice koje otvorite u sesijama učenja i testiranja.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'it', 'Le materie sono la principale unità di studio. Contengono le carte che apri nelle sessioni di apprendimento e test.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'lv', 'Priekšmeti ir galvenā mācību vienība. Tajos ir kartītes, ko atverat mācīšanās un pārbaudes sesijās.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'lt', 'Dalykai yra pagrindinis studijų vienetas. Juose laikomos kortelės, kurias atidarote mokymosi ir testavimo seansuose.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'hu', 'A tantárgyak jelentik a tanulás fő egységét. Ők tartják a kártyákat, amelyeket a Tanulás és a Teszt munkamenetekben kinyit.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'mt', 'Is-suġġetti huma l-unità ewlenija ta’ studju. Huma jżommu l-karti li tiftaħ fis-sessjonijiet ta'' Tgħallem u Test.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'nl', 'Onderwerpen vormen de belangrijkste onderwijseenheid. Ze bevatten de kaarten die u opent tijdens leer- en testsessies.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'pl', 'Przedmioty są główną jednostką studiów. Zawierają karty, które otwierasz w sesjach nauki i testowania.', CURRENT_TIMESTAMP)
INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('about_organize_subjects_desc', 'pt', 'Os assuntos são a principal unidade de estudo. Eles contêm os cartões que você abre nas sessões de aprendizado e teste.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'ro', 'Subiectele sunt unitatea principală de studiu. Ei dețin cardurile pe care le deschideți în sesiunile de Învățare și Testare.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'sk', 'Predmety sú hlavnou jednotkou štúdia. Držia karty, ktoré otvoríte v reláciách učenia a testovania.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'sl', 'Predmeti so glavna učna enota. Imajo kartice, ki jih odprete na sejah učenja in testiranja.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'fi', 'Aineet ovat opiskelun pääyksikkö. Heillä on oppimis- ja testausistunnoissa avaamasi kortit.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'sv', 'Ämnen är den huvudsakliga studieenheten. De håller korten du öppnar i Learn and Test-sessioner.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'tl', 'Ang mga paksa ay ang pangunahing yunit ng pag-aaral. Hawak nila ang mga card na binuksan mo sa mga session ng Matuto at Pagsubok.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'vi', 'Môn học là đơn vị học tập chính. Họ giữ các thẻ bạn mở trong các buổi Học và Kiểm tra.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'tr', 'Konular çalışmanın ana birimidir. Öğrenme ve Test oturumlarında açtığınız kartları tutarlar.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'el', 'Τα θέματα είναι η κύρια μονάδα μελέτης. Διατηρούν τις κάρτες που ανοίγετε στις συνεδρίες εκμάθησης και δοκιμής.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'uk', 'Предмети є основною одиницею навчання. У них зберігаються картки, які ви відкриваєте під час навчання та тестування.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'ar', 'المواد هي الوحدة الرئيسية للدراسة. إنهم يحملون البطاقات التي تفتحها في جلسات التعلم والاختبار.', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'hi', 'विषय अध्ययन की मुख्य इकाई हैं। वे आपके द्वारा लर्न और टेस्ट सत्र में खोले गए कार्ड रखते हैं।', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'zh', '科目是学习的主要单位。他们保存您在学习和测试课程中打开的卡片。', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'ja', '科目は学習の主な単位です。学習セッションとテスト セッションで開いたカードが保持されます。', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'ko', '과목은 학습의 주요 단위입니다. 학습 및 테스트 세션에서 연 카드를 보관합니다.', CURRENT_TIMESTAMP),
