  ('about_organize_title', 'ko', '콘텐츠 구성 방법', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'en', 'Your profile lets you tune daily goal targets, learn session size, test session size, and number of answers.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'id', 'Profil Anda memungkinkan Anda menyesuaikan target sasaran harian, mempelajari ukuran sesi, ukuran sesi tes, dan jumlah jawaban.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'bg', 'Вашият профил ви позволява да настройвате дневните цели, да научите размера на сесията, размера на тестовата сесия и броя на отговорите.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'cs', 'Váš profil vám umožňuje vyladit denní cíle, zjistit velikost relace, velikost testovací relace a počet odpovědí.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'da', 'Din profil giver dig mulighed for at indstille daglige mål, lære sessionsstørrelse, testsessionstørrelse og antal svar.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'de', 'Mit Ihrem Profil können Sie die täglichen Zielvorgaben, die Lernsitzungsgröße, die Testsitzungsgröße und die Anzahl der Antworten anpassen.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'et', 'Teie profiil võimaldab teil häälestada igapäevaseid eesmärke, teada saada seansi suurust, testseansi suurust ja vastuste arvu.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'es', 'Su perfil le permite ajustar sus objetivos diarios, conocer el tamaño de la sesión, el tamaño de la sesión de prueba y la cantidad de respuestas.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'fr', 'Votre profil vous permet d''ajuster vos objectifs quotidiens, de connaître la taille de la session, la taille de la session de test et le nombre de réponses.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'ga', 'Ligeann do phróifíl duit spriocanna laethúla sprice a choigeartú, méid an tseisiúin a fhoghlaim, méid an tseisiúin tástála, agus líon na bhfreagraí.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'hr', 'Vaš profil omogućuje podešavanje dnevnih ciljeva, učenje veličine sesije, veličine testne sesije i broja odgovora.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'it', 'Il tuo profilo ti consente di ottimizzare gli obiettivi giornalieri, apprendere la dimensione della sessione, la dimensione della sessione di test e il numero di risposte.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'lv', 'Jūsu profils ļauj pielāgot ikdienas mērķus, uzzināt sesijas lielumu, testa sesijas lielumu un atbilžu skaitu.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'lt', 'Savo profilyje galite nustatyti dienos tikslus, sužinoti sesijos dydį, bandomosios sesijos dydį ir atsakymų skaičių.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'hu', 'Profilja segítségével beállíthatja a napi célokat, megtudhatja a munkamenet méretét, a tesztmunkamenet méretét és a válaszok számát.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'mt', 'Il-profil tiegħek iħallik tirranġa l-miri tal-miri ta’ kuljum, titgħallem id-daqs tas-sessjoni, id-daqs tas-sessjoni tat-test, u n-numru ta’ tweġibiet.', CURRENT_TIMESTAMP)
INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('about_progress_goals_desc', 'nl', 'Met uw profiel kunt u de dagelijkse doeldoelen afstemmen, de sessiegrootte, de testsessiegrootte en het aantal antwoorden leren.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'pl', 'Twój profil umożliwia dostrojenie dziennych celów, poznanie rozmiaru sesji, rozmiaru sesji testowej i liczby odpowiedzi.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'pt', 'Seu perfil permite ajustar metas diárias, saber o tamanho da sessão, o tamanho da sessão de teste e o número de respostas.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'ro', 'Profilul vă permite să reglați obiectivele zilnice, să aflați dimensiunea sesiunii, dimensiunea sesiunii de testare și numărul de răspunsuri.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'sk', 'Váš profil vám umožňuje vyladiť denné ciele, zistiť veľkosť relácie, veľkosť testovacej relácie a počet odpovedí.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'sl', 'Vaš profil vam omogoča prilagajanje dnevnih ciljev, učenje velikosti seje, velikost testne seje in število odgovorov.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'fi', 'Profiilisi avulla voit säätää päivittäisiä tavoitteita, oppia istunnon kokoa, testiistunnon kokoa ja vastausten määrää.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'sv', 'Din profil låter dig ställa in dagliga mål, lära dig sessionsstorlek, testsessionsstorlek och antal svar.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'tl', 'Hinahayaan ka ng iyong profile na ibagay ang mga pang-araw-araw na target ng layunin, matutunan ang laki ng session, sukat ng session ng pagsubok, at bilang ng mga sagot.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'vi', 'Hồ sơ của bạn cho phép bạn điều chỉnh các mục tiêu mục tiêu hàng ngày, tìm hiểu quy mô phiên, quy mô phiên kiểm tra và số lượng câu trả lời.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'tr', 'Profiliniz günlük hedef hedeflerinizi ayarlamanıza, oturum boyutunu, test oturumu boyutunu ve yanıt sayısını öğrenmenize olanak tanır.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'el', 'Το προφίλ σας σάς επιτρέπει να συντονίζετε τους ημερήσιους στόχους στόχων, να μαθαίνετε το μέγεθος της περιόδου σύνδεσης, το μέγεθος της δοκιμαστικής περιόδου λειτουργίας και τον αριθμό των απαντήσεων.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'uk', 'Ваш профіль дозволяє налаштовувати щоденні цілі, вивчати розмір сеансу, розмір тестового сеансу та кількість відповідей.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'ar', 'يتيح لك ملفك الشخصي ضبط أهداف الأهداف اليومية ومعرفة حجم الجلسة واختبار حجم الجلسة وعدد الإجابات.', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'hi', 'आपकी प्रोफ़ाइल आपको दैनिक लक्ष्य निर्धारित करने, सत्र का आकार, परीक्षण सत्र का आकार और उत्तरों की संख्या जानने की सुविधा देती है।', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'zh', '您的个人资料可让您调整每日目标、学习会话大小、测试会话大小和答案数量。', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'ja', 'プロファイルを使用すると、毎日の目標目標を調整したり、学習セッションのサイズ、テスト セッションのサイズ、回答数を調整したりできます。', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'ko', '프로필을 사용하면 일일 목표 목표를 조정하고 세션 크기, 테스트 세션 크기 및 답변 수를 알아볼 수 있습니다.', CURRENT_TIMESTAMP),
