  ('about_progress_goals_title', 'ar', 'الأهداف اليومية وإعدادات الجلسة', CURRENT_TIMESTAMP),
  ('about_progress_goals_title', 'hi', 'दैनिक लक्ष्य और सत्र सेटिंग', CURRENT_TIMESTAMP),
