  ('about_support_onboarding_title', 'zh', '入职', CURRENT_TIMESTAMP),
  ('about_support_onboarding_title', 'ja', 'オンボーディング', CURRENT_TIMESTAMP),
  ('about_support_onboarding_title', 'ko', '온보딩', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'en', 'UI language, theme mode, theme color, sound, sidebar placement, and documentation visibility can all be adjusted from settings.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'id', 'Bahasa UI, mode tema, warna tema, suara, penempatan sidebar, dan visibilitas dokumentasi semuanya dapat disesuaikan dari pengaturan.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'bg', 'Езикът на потребителския интерфейс, режимът на темата, цветът на темата, звукът, разположението на страничната лента и видимостта на документацията могат да се регулират от настройките.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'cs', 'Jazyk uživatelského rozhraní, režim motivu, barvu motivu, zvuk, umístění postranního panelu a viditelnost dokumentace lze upravit v nastavení.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'da', 'Brugergrænsefladesprog, tematilstand, temafarve, lyd, sidebjælkeplacering og dokumentationssynlighed kan alle justeres fra indstillingerne.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'de', 'Die Sprache der Benutzeroberfläche, der Designmodus, die Designfarbe, der Ton, die Platzierung der Seitenleiste und die Sichtbarkeit der Dokumentation können alle über die Einstellungen angepasst werden.', CURRENT_TIMESTAMP)
INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('about_support_settings_desc', 'et', 'Kasutajaliidese keelt, teemarežiimi, teema värvi, heli, külgriba paigutust ja dokumentatsiooni nähtavust saab seadetest reguleerida.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'es', 'El idioma de la interfaz de usuario, el modo del tema, el color del tema, el sonido, la ubicación de la barra lateral y la visibilidad de la documentación se pueden ajustar desde la configuración.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'fr', 'La langue de l''interface utilisateur, le mode thème, la couleur du thème, le son, l''emplacement de la barre latérale et la visibilité de la documentation peuvent tous être ajustés à partir des paramètres.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'ga', 'Is féidir teanga Chomhéadain, modh téama, dath téama, fuaim, socrúchán barra taoibh, agus infheictheacht doiciméadaithe a choigeartú ó na socruithe.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'hr', 'Jezik korisničkog sučelja, način rada teme, boja teme, zvuk, položaj bočne trake i vidljivost dokumentacije mogu se podesiti iz postavki.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'it', 'La lingua dell''interfaccia utente, la modalità del tema, il colore del tema, il suono, il posizionamento della barra laterale e la visibilità della documentazione possono essere regolati dalle impostazioni.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'lv', 'UI valodu, motīva režīmu, motīva krāsu, skaņu, sānjoslas izvietojumu un dokumentācijas redzamību var pielāgot iestatījumos.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'lt', 'UI kalbą, temos režimą, temos spalvą, garsą, šoninės juostos vietą ir dokumentacijos matomumą galima reguliuoti nustatymuose.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'hu', 'A felhasználói felület nyelve, a téma mód, a téma színe, a hang, az oldalsáv elhelyezése és a dokumentáció láthatósága mind beállíthatók a beállításokból.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'mt', 'Il-lingwa tal-UI, il-mod tat-tema, il-kulur tat-tema, il-ħoss, it-tqegħid tal-sidebar, u l-viżibilità tad-dokumentazzjoni kollha jistgħu jiġu aġġustati mis-settings.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'nl', 'UI-taal, themamodus, themakleur, geluid, plaatsing van de zijbalk en zichtbaarheid van de documentatie kunnen allemaal worden aangepast via de instellingen.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'pl', 'Język interfejsu użytkownika, tryb motywu, kolor motywu, dźwięk, rozmieszczenie paska bocznego i widoczność dokumentacji można dostosować w ustawieniach.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'pt', 'O idioma da interface do usuário, o modo do tema, a cor do tema, o som, o posicionamento da barra lateral e a visibilidade da documentação podem ser ajustados nas configurações.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'ro', 'Limba interfeței de utilizare, modul temă, culoarea temei, sunetul, plasarea barei laterale și vizibilitatea documentației pot fi ajustate din setări.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'sk', 'Jazyk používateľského rozhrania, režim témy, farbu témy, zvuk, umiestnenie bočného panela a viditeľnosť dokumentácie je možné upraviť v nastaveniach.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'sl', 'Jezik uporabniškega vmesnika, način teme, barvo teme, zvok, postavitev stranske vrstice in vidnost dokumentacije lahko prilagodite v nastavitvah.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'fi', 'Käyttöliittymän kieltä, teematilaa, teeman väriä, ääntä, sivupalkin sijoittelua ja dokumentaation näkyvyyttä voidaan säätää asetuksista.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'sv', 'Användargränssnittsspråk, temaläge, temafärg, ljud, sidofältsplacering och dokumentationssynlighet kan alla justeras från inställningarna.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'tl', 'Ang wika ng UI, mode ng tema, kulay ng tema, tunog, pagkakalagay sa sidebar, at visibility ng dokumentasyon ay maaaring isaayos lahat mula sa mga setting.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'vi', 'Ngôn ngữ giao diện người dùng, chế độ chủ đề, màu chủ đề, âm thanh, vị trí thanh bên và khả năng hiển thị tài liệu đều có thể được điều chỉnh từ cài đặt.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'tr', 'Kullanıcı arayüzü dili, tema modu, tema rengi, ses, kenar çubuğu yerleşimi ve belgelerin görünürlüğü ayarlardan ayarlanabilir.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'el', 'Η γλώσσα διεπαφής χρήστη, η λειτουργία θέματος, το χρώμα θέματος, ο ήχος, η τοποθέτηση της πλευρικής γραμμής και η ορατότητα της τεκμηρίωσης μπορούν να προσαρμοστούν από τις ρυθμίσεις.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'uk', 'Мову інтерфейсу користувача, режим теми, колір теми, звук, розташування бічної панелі та видимість документації можна налаштувати в налаштуваннях.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'ar', 'يمكن تعديل لغة واجهة المستخدم ووضع السمة ولون السمة والصوت وموضع الشريط الجانبي ورؤية الوثائق من الإعدادات.', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'hi', 'यूआई भाषा, थीम मोड, थीम रंग, ध्वनि, साइडबार प्लेसमेंट और दस्तावेज़ीकरण दृश्यता सभी को सेटिंग्स से समायोजित किया जा सकता है।', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'zh', 'UI 语言、主题模式、主题颜色、声音、侧边栏位置和文档可见性都可以通过设置进行调整。', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'ja', 'UI 言語、テーマ モード、テーマの色、サウンド、サイドバーの配置、ドキュメントの表示/非表示はすべて設定から調整できます。', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'ko', 'UI 언어, 테마 모드, 테마 색상, 사운드, 사이드바 배치 및 문서 가시성은 모두 설정에서 조정할 수 있습니다.', CURRENT_TIMESTAMP),
