  ('doc_create_model_title', 'el', 'Μοντέλο Περιεχομένου', CURRENT_TIMESTAMP),
  ('doc_create_model_title', 'uk', 'Модель вмісту', CURRENT_TIMESTAMP),
  ('doc_create_model_title', 'ar', 'نموذج المحتوى', CURRENT_TIMESTAMP),
  ('doc_create_model_title', 'hi', 'सामग्री मॉडल', CURRENT_TIMESTAMP),
  ('doc_create_model_title', 'zh', '内容模型', CURRENT_TIMESTAMP),
  ('doc_create_model_title', 'ja', 'コンテンツモデル', CURRENT_TIMESTAMP),
  ('doc_create_model_title', 'ko', '콘텐츠 모델', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'en', 'Use "mine" to work on your own content, favorites to pin useful items, and public library to browse shared material. Public visibility affects discovery, while ownership affects what you can edit or delete.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'id', 'Gunakan "milikku" untuk mengerjakan konten Anda sendiri, favorit untuk menyematkan item berguna, dan perpustakaan umum untuk menelusuri materi yang dibagikan. Visibilitas publik memengaruhi penemuan, sedangkan kepemilikan memengaruhi apa yang dapat Anda edit atau hapus.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'bg', 'Използвайте „moy“, за да работите върху собственото си съдържание, любими, за да закачите полезни елементи, и публична библиотека, за да разглеждате споделен материал. Публичната видимост засяга откриването, докато собствеността влияе върху това, което можете да редактирате или изтриете.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'cs', 'Použijte „moje“ k práci na svém vlastním obsahu, oblíbené položky k připnutí užitečných položek a veřejnou knihovnu k procházení sdílených materiálů. Veřejná viditelnost ovlivňuje zjišťování, zatímco vlastnictví ovlivňuje, co můžete upravit nebo smazat.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'da', 'Brug "mine" til at arbejde med dit eget indhold, favoritter til at fastgøre nyttige genstande og offentligt bibliotek til at gennemse delt materiale. Offentlig synlighed påvirker opdagelse, mens ejerskab påvirker, hvad du kan redigere eller slette.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'de', 'Verwenden Sie „Meine“, um an Ihren eigenen Inhalten zu arbeiten, „Favoriten“, um nützliche Elemente anzuheften, und „Öffentliche Bibliothek“, um geteiltes Material zu durchsuchen. Die öffentliche Sichtbarkeit wirkt sich auf die Auffindbarkeit aus, während sich der Besitz darauf auswirkt, was Sie bearbeiten oder löschen können.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'et', 'Kasutage "minu" oma sisu kallal töötamiseks, lemmikuid kasulike üksuste kinnitamiseks ja avalikku raamatukogu jagatud materjalide sirvimiseks. Avalik nähtavus mõjutab avastamist, samas kui omandiline kuuluvus mõjutab seda, mida saate muuta või kustutada.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'es', 'Utilice "mío" para trabajar en su propio contenido, favoritos para fijar elementos útiles y biblioteca pública para explorar material compartido. La visibilidad pública afecta el descubrimiento, mientras que la propiedad afecta lo que puedes editar o eliminar.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'fr', 'Utilisez « le mien » pour travailler sur votre propre contenu, les favoris pour épingler des éléments utiles et la bibliothèque publique pour parcourir le matériel partagé. La visibilité publique affecte la découverte, tandis que la propriété affecte ce que vous pouvez modifier ou supprimer.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'ga', 'Úsáid "mianach" chun oibriú ar d''inneachar féin, ceanáin chun míreanna úsáideacha a phionnadh, agus leabharlann phoiblí chun ábhar comhroinnte a bhrabhsáil. Bíonn tionchar ag infheictheacht phoiblí ar fhionnachtain, agus bíonn tionchar ag úinéireacht ar an méid is féidir leat a chur in eagar nó a scriosadh.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'hr', 'Koristite "moje" za rad na vlastitom sadržaju, favorite za prikvačivanje korisnih stavki i javnu biblioteku za pregledavanje zajedničkog materijala. Javna vidljivost utječe na otkrivanje, dok vlasništvo utječe na ono što možete uređivati ​​ili brisati.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'it', 'Utilizza "mio" per lavorare sui tuoi contenuti, i preferiti per appuntare elementi utili e la libreria pubblica per sfogliare il materiale condiviso. La visibilità pubblica influisce sulla scoperta, mentre la proprietà influisce su ciò che puoi modificare o eliminare.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'lv', 'Izmantojiet "manējo", lai strādātu pie sava satura, izlasi, lai piespraustu noderīgus vienumus, un publisko bibliotēku, lai pārlūkotu koplietoto materiālu. Publiskā redzamība ietekmē atklāšanu, savukārt īpašumtiesības ietekmē to, ko varat rediģēt vai dzēst.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'lt', 'Naudokite „mano“ norėdami dirbti su savo turiniu, parankinius, kad prisegtumėte naudingų elementų, ir viešąją biblioteką, kad naršytumėte bendrinamą medžiagą. Viešas matomumas turi įtakos atradimui, o nuosavybės teisė – ką galite redaguoti ar ištrinti.', CURRENT_TIMESTAMP)
INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('doc_create_visibility_desc', 'hu', 'Használja az „enyémet” a saját tartalmain való munkához, a kedvenceket a hasznos elemek rögzítéséhez, a nyilvános könyvtárat pedig a megosztott anyagok böngészéséhez. A nyilvános láthatóság befolyásolja a felfedezést, míg a tulajdonjog azt, hogy mit szerkeszthet vagy törölhet.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'mt', 'Uża "minjiera" biex taħdem fuq il-kontenut tiegħek stess, favoriti biex tippinja oġġetti utli, u librerija pubblika biex tfittex materjal kondiviż. Il-viżibilità pubblika taffettwa l-iskoperta, filwaqt li s-sjieda taffettwa dak li tista’ teditja jew tħassar.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'nl', 'Gebruik ''mijn'' om aan uw eigen inhoud te werken, favorieten om nuttige items vast te zetten en de openbare bibliotheek om door gedeeld materiaal te bladeren. Publieke zichtbaarheid heeft invloed op de ontdekking, terwijl eigendom invloed heeft op wat u kunt bewerken of verwijderen.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'pl', 'Użyj opcji „moje”, aby pracować nad własną zawartością, ulubionych, aby przypiąć przydatne elementy, a biblioteki publicznej, aby przeglądać udostępnione materiały. Publiczna widoczność wpływa na odkrywanie, a własność wpływa na to, co możesz edytować lub usunąć.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'pt', 'Use "meu" para trabalhar em seu próprio conteúdo, favoritos para fixar itens úteis e biblioteca pública para navegar pelo material compartilhado. A visibilidade pública afeta a descoberta, enquanto a propriedade afeta o que você pode editar ou excluir.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'ro', 'Folosiți „al meu” pentru a lucra la propriul conținut, favoritele pentru a fixa elemente utile și biblioteca publică pentru a răsfoi materialele partajate. Vizibilitatea publică afectează descoperirea, în timp ce calitatea de proprietar afectează ceea ce puteți edita sau șterge.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'sk', 'Použite „moje“ na prácu na svojom vlastnom obsahu, obľúbené položky na pripnutie užitočných položiek a verejnú knižnicu na prehliadanie zdieľaného materiálu. Verejná viditeľnosť ovplyvňuje objavovanie, zatiaľ čo vlastníctvo ovplyvňuje to, čo môžete upraviť alebo odstrániť.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'sl', 'Uporabite »moje« za delo na lastni vsebini, priljubljene za pripenjanje uporabnih predmetov in javno knjižnico za brskanje po skupnem gradivu. Javna vidnost vpliva na odkrivanje, medtem ko lastništvo vpliva na to, kaj lahko uredite ali izbrišete.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'fi', 'Käytä "minun" työstääksesi omaa sisältöäsi, suosikkeja kiinnittääksesi hyödyllisiä kohteita ja julkista kirjastoa selataksesi jaettua materiaalia. Julkinen näkyvyys vaikuttaa löytämiseen, kun taas omistajuus vaikuttaa siihen, mitä voit muokata tai poistaa.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'sv', 'Använd "min" för att arbeta med ditt eget innehåll, favoriter för att fästa användbara föremål och offentligt bibliotek för att bläddra i delat material. Offentlig synlighet påverkar upptäckten, medan äganderätten påverkar vad du kan redigera eller ta bort.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'tl', 'Gamitin ang "akin" para gumawa sa sarili mong content, mga paborito para i-pin ang mga kapaki-pakinabang na item, at pampublikong library para mag-browse ng nakabahaging materyal. Ang pampublikong visibility ay nakakaapekto sa pagtuklas, habang ang pagmamay-ari ay nakakaapekto sa kung ano ang maaari mong i-edit o tanggalin.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'vi', 'Sử dụng "của tôi" để làm việc trên nội dung của riêng bạn, mục yêu thích để ghim các mục hữu ích và thư viện công cộng để duyệt tài liệu được chia sẻ. Khả năng hiển thị công khai ảnh hưởng đến khả năng khám phá, trong khi quyền sở hữu ảnh hưởng đến nội dung bạn có thể chỉnh sửa hoặc xóa.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'tr', 'Kendi içeriğiniz üzerinde çalışmak için "benimki"yi, faydalı öğeleri sabitlemek için favorilerinizi ve paylaşılan materyale göz atmak için halk kütüphanesini kullanın. Herkese açık görünürlük, keşfi etkilerken sahiplik, neyi düzenleyebileceğinizi veya silebileceğinizi etkiler.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'el', 'Χρησιμοποιήστε το "δικό μου" για να εργαστείτε στο δικό σας περιεχόμενο, τα αγαπημένα για να καρφιτσώσετε χρήσιμα αντικείμενα και τη δημόσια βιβλιοθήκη για να περιηγηθείτε σε κοινόχρηστο υλικό. Η δημόσια ορατότητα επηρεάζει την ανακάλυψη, ενώ η ιδιοκτησία επηρεάζει το τι μπορείτε να επεξεργαστείτε ή να διαγράψετε.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'uk', 'Використовуйте «мій», щоб працювати над власним вмістом, вибране, щоб закріплювати корисні елементи, і публічну бібліотеку, щоб переглядати спільний матеріал. Видимість для всіх впливає на виявлення, тоді як право власності впливає на те, що ви можете редагувати або видаляти.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'ar', 'استخدم "الخاص بي" للعمل على المحتوى الخاص بك، والمفضلات لتثبيت العناصر المفيدة، والمكتبة العامة لتصفح المواد المشتركة. تؤثر الرؤية العامة على الاكتشاف، بينما تؤثر الملكية على ما يمكنك تعديله أو حذفه.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'hi', 'अपनी सामग्री पर काम करने के लिए "मेरा", उपयोगी वस्तुओं को पिन करने के लिए पसंदीदा और साझा सामग्री ब्राउज़ करने के लिए सार्वजनिक लाइब्रेरी का उपयोग करें। सार्वजनिक दृश्यता खोज को प्रभावित करती है, जबकि स्वामित्व प्रभावित करता है कि आप क्या संपादित या हटा सकते हैं।', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'zh', '使用“我的”来处理您自己的内容，使用收藏夹来固定有用的项目，使用公共图书馆来浏览共享材料。公众可见性影响发现，而所有权影响您可以编辑或删除的内容。', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'ja', '自分のコンテンツに取り組むには「mine」を使用し、便利なアイテムを固定するにはお気に入りを、共有マテリアルを閲覧するには公共ライブラリを使用します。公開可視性は検出に影響しますが、所有権は編集または削除できる内容に影響します。', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'ko', '자신만의 콘텐츠를 작업하려면 "내 것"을 사용하고, 유용한 항목을 고정하려면 즐겨찾기를 사용하고, 공유 자료를 검색하려면 공용 라이브러리를 사용하세요. 공개 공개 여부는 검색에 영향을 미치는 반면 소유권은 편집하거나 삭제할 수 있는 항목에 영향을 미칩니다.', CURRENT_TIMESTAMP),
