  ('doc_start_feedback_title', 'uk', 'Зворотній зв''язок і допомога', CURRENT_TIMESTAMP),
  ('doc_start_feedback_title', 'ar', 'ردود الفعل والمساعدة', CURRENT_TIMESTAMP),
  ('doc_start_feedback_title', 'hi', 'प्रतिक्रिया और सहायता', CURRENT_TIMESTAMP),
  ('doc_start_feedback_title', 'zh', '反馈和帮助', CURRENT_TIMESTAMP),
  ('doc_start_feedback_title', 'ja', 'フィードバックとヘルプ', CURRENT_TIMESTAMP),
  ('doc_start_feedback_title', 'ko', '피드백 및 도움말', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'en', 'Use this tab when you are learning how the dashboard, library, progress, and social features fit together.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'id', 'Gunakan tab ini saat Anda mempelajari bagaimana dasbor, perpustakaan, kemajuan, dan fitur sosial saling terkait.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'bg', 'Използвайте този раздел, когато научавате как таблото за управление, библиотеката, напредъкът и социалните функции си пасват.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'cs', 'Tuto kartu použijte, když se učíte, jak do sebe zapadají řídicí panel, knihovna, pokrok a sociální funkce.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'da', 'Brug denne fane, når du lærer, hvordan dashboard, bibliotek, fremskridt og sociale funktioner passer sammen.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'de', 'Verwenden Sie diese Registerkarte, wenn Sie lernen, wie Dashboard, Bibliothek, Fortschritt und soziale Funktionen zusammenpassen.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'et', 'Kasutage seda vahekaarti, kui õpite, kuidas armatuurlaud, kogu, edenemine ja suhtlusfunktsioonid omavahel sobivad.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'es', 'Utilice esta pestaña cuando esté aprendiendo cómo encajan el panel, la biblioteca, el progreso y las funciones sociales.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'fr', 'Utilisez cet onglet lorsque vous découvrez comment le tableau de bord, la bibliothèque, la progression et les fonctionnalités sociales s''articulent.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'ga', 'Bain úsáid as an táb seo agus tú ag foghlaim conas a oireann an painéal, an leabharlann, an dul chun cinn agus na gnéithe sóisialta le chéile.', CURRENT_TIMESTAMP)
INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('doc_start_intro_desc', 'hr', 'Koristite ovu karticu kada učite kako se nadzorna ploča, biblioteka, napredak i društvene značajke uklapaju zajedno.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'it', 'Utilizza questa scheda per imparare come si integrano dashboard, libreria, avanzamento e funzionalità social.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'lv', 'Izmantojiet šo cilni, kad apgūstat informācijas paneļa, bibliotēkas, progresa un sociālo funkciju saderību.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'lt', 'Naudokite šį skirtuką, kai sužinosite, kaip prietaisų skydelis, biblioteka, pažanga ir socialinės funkcijos dera tarpusavyje.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'hu', 'Használja ezt a lapot, ha megtudja, hogyan illeszkednek egymáshoz az irányítópult, a könyvtár, az előrehaladás és a közösségi funkciók.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'mt', 'Uża din it-tab meta tkun qed titgħallem kif id-daxxbord, il-librerija, il-progress u l-karatteristiċi soċjali jaqblu flimkien.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'nl', 'Gebruik dit tabblad als u leert hoe het dashboard, de bibliotheek, de voortgang en de sociale functies in elkaar passen.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'pl', 'Użyj tej karty, aby dowiedzieć się, jak pulpit nawigacyjny, biblioteka, postęp i funkcje społecznościowe pasują do siebie.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'pt', 'Use esta guia quando estiver aprendendo como o painel, a biblioteca, o progresso e os recursos sociais se encaixam.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'ro', 'Utilizați această filă atunci când aflați cum se potrivesc tabloul de bord, biblioteca, progresul și funcțiile sociale.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'sk', 'Túto kartu použite, keď sa naučíte, ako do seba zapadajú hlavný panel, knižnica, pokrok a sociálne funkcie.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'sl', 'Uporabite ta zavihek, ko se učite, kako se nadzorna plošča, knjižnica, napredek in družabne funkcije ujemajo.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'fi', 'Käytä tätä välilehteä, kun opit kuinka kojelauta, kirjasto, edistyminen ja sosiaaliset ominaisuudet sopivat yhteen.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'sv', 'Använd den här fliken när du lär dig hur instrumentpanelen, biblioteket, framsteg och sociala funktioner passar ihop.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'tl', 'Gamitin ang tab na ito kapag natututo ka kung paano magkatugma ang dashboard, library, pag-unlad, at mga social na feature.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'vi', 'Sử dụng tab này khi bạn đang tìm hiểu cách bảng điều khiển, thư viện, tiến trình và các tính năng xã hội khớp với nhau như thế nào.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'tr', 'Kontrol panelinin, kitaplığın, ilerlemenin ve sosyal özelliklerin birbirine nasıl uyduğunu öğrenirken bu sekmeyi kullanın.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'el', 'Χρησιμοποιήστε αυτήν την καρτέλα όταν μαθαίνετε πώς ταιριάζουν μεταξύ τους οι λειτουργίες του πίνακα ελέγχου, της βιβλιοθήκης, της προόδου και των κοινωνικών δικτύων.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'uk', 'Використовуйте цю вкладку, коли вивчаєте, як поєднуються інформаційна панель, бібліотека, прогрес і соціальні функції.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'ar', 'استخدم علامة التبويب هذه عندما تتعلم كيفية توافق لوحة المعلومات والمكتبة والتقدم والميزات الاجتماعية معًا.', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'hi', 'इस टैब का उपयोग तब करें जब आप सीख रहे हों कि डैशबोर्ड, लाइब्रेरी, प्रगति और सामाजिक सुविधाएँ एक साथ कैसे फिट होती हैं।', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'zh', '当您了解仪表板、库、进度和社交功能如何组合在一起时，请使用此选项卡。', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'ja', 'このタブは、ダッシュボード、ライブラリ、進捗状況、ソーシャル機能がどのように連携するかを学習するときに使用します。', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'ko', '대시보드, 라이브러리, 진행 상황 및 소셜 기능이 어떻게 조화를 이루는지 알아볼 때 이 탭을 사용하세요.', CURRENT_TIMESTAMP),
  ('doc_start_intro_title', 'en', 'Getting Started', CURRENT_TIMESTAMP),
  ('doc_start_intro_title', 'id', 'Memulai', CURRENT_TIMESTAMP),
  ('doc_start_intro_title', 'bg', 'Първи стъпки', CURRENT_TIMESTAMP),
  ('doc_start_intro_title', 'cs', 'Začínáme', CURRENT_TIMESTAMP),
  ('doc_start_intro_title', 'da', 'Kom godt i gang', CURRENT_TIMESTAMP),
