  ('doc_study_intro_title', 'el', 'Μελέτη', CURRENT_TIMESTAMP),
  ('doc_study_intro_title', 'uk', 'Дослідження', CURRENT_TIMESTAMP),
  ('doc_study_intro_title', 'ar', 'يذاكر', CURRENT_TIMESTAMP),
  ('doc_study_intro_title', 'hi', 'अध्ययन', CURRENT_TIMESTAMP),
  ('doc_study_intro_title', 'zh', '学习', CURRENT_TIMESTAMP),
  ('doc_study_intro_title', 'ja', '勉強', CURRENT_TIMESTAMP),
  ('doc_study_intro_title', 'ko', '공부하다', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'en', 'When media is available, use it to reinforce pronunciation and recognition. Autoplay is most useful for passive review or repeated listening during shorter sessions.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'id', 'Jika media tersedia, gunakan media tersebut untuk memperkuat pengucapan dan pengenalan. Putar otomatis paling berguna untuk tinjauan pasif atau mendengarkan berulang kali selama sesi yang lebih singkat.', CURRENT_TIMESTAMP)
INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('doc_study_media_desc', 'bg', 'Когато има налична медия, използвайте я, за да подсилите произношението и разпознаването. Автоматичното пускане е най-полезно за пасивен преглед или многократно слушане по време на по-кратки сесии.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'cs', 'Když jsou k dispozici média, použijte je k posílení výslovnosti a rozpoznávání. Automatické přehrávání je nejužitečnější pro pasivní kontrolu nebo opakované poslouchání během kratších relací.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'da', 'Når medier er tilgængelige, skal du bruge dem til at styrke udtale og genkendelse. Autoplay er mest nyttigt til passiv gennemgang eller gentagen lytning under kortere sessioner.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'de', 'Wenn Medien verfügbar sind, nutzen Sie diese, um die Aussprache und Erkennung zu verbessern. Autoplay ist am nützlichsten für die passive Wiedergabe oder das wiederholte Hören während kürzerer Sitzungen.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'et', 'Kui meedia on saadaval, kasutage seda häälduse ja äratundmise tugevdamiseks. Automaatne esitus on kõige kasulikum passiivseks ülevaatuseks või korduvaks kuulamiseks lühemate seansside ajal.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'es', 'Cuando haya medios disponibles, utilícelos para reforzar la pronunciación y el reconocimiento. La reproducción automática es más útil para la revisión pasiva o la escucha repetida durante sesiones más cortas.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'fr', 'Lorsque des médias sont disponibles, utilisez-les pour renforcer la prononciation et la reconnaissance. La lecture automatique est particulièrement utile pour une révision passive ou une écoute répétée lors de sessions plus courtes.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'ga', 'Nuair a bhíonn na meáin ar fáil, bain úsáid as chun fuaimniú agus aitheantas a threisiú. Tá an t-uathsheinm an-úsáideach le haghaidh athbhreithniú éighníomhach nó éisteacht arís agus arís eile le linn seisiúin níos giorra.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'hr', 'Kada su mediji dostupni, koristite ih za učvršćivanje izgovora i prepoznavanja. Automatska reprodukcija najkorisnija je za pasivni pregled ili ponovljeno slušanje tijekom kraćih sesija.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'it', 'Quando i media sono disponibili, usali per rafforzare la pronuncia e il riconoscimento. La riproduzione automatica è particolarmente utile per la revisione passiva o l''ascolto ripetuto durante sessioni più brevi.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'lv', 'Kad multivide ir pieejama, izmantojiet to, lai pastiprinātu izrunu un atpazīšanu. Automātiskā atskaņošana ir visnoderīgākā pasīvai pārskatīšanai vai atkārtotai klausīšanai īsāku sesiju laikā.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'lt', 'Kai yra medija, naudokite ją tarimui ir atpažinimui sustiprinti. Automatinis paleidimas yra naudingiausias pasyviai peržiūrint arba pakartotinai klausantis trumpesnių seansų metu.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'hu', 'Ha rendelkezésre áll média, használja a kiejtés és a felismerés megerősítésére. Az automatikus lejátszás a leghasznosabb passzív áttekintéshez vagy rövidebb munkamenetek során történő ismételt hallgatáshoz.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'mt', 'Meta l-midja tkun disponibbli, użaha biex issaħħaħ il-pronunzja u r-rikonoxximent. Autoplay huwa l-aktar utli għal reviżjoni passiva jew smigħ ripetut waqt sessjonijiet iqsar.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'nl', 'Als er media beschikbaar zijn, gebruik deze dan om de uitspraak en herkenning te versterken. Autoplay is vooral handig voor passieve beoordeling of herhaald luisteren tijdens kortere sessies.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'pl', 'Jeśli media są dostępne, użyj ich, aby wzmocnić wymowę i rozpoznawanie. Autoodtwarzanie jest najbardziej przydatne w przypadku pasywnego przeglądania lub wielokrotnego słuchania podczas krótszych sesji.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'pt', 'Quando houver mídia disponível, use-a para reforçar a pronúncia e o reconhecimento. A reprodução automática é mais útil para revisão passiva ou audição repetida durante sessões mais curtas.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'ro', 'Când media este disponibilă, utilizați-l pentru a consolida pronunția și recunoașterea. Redarea automată este cea mai utilă pentru revizuirea pasivă sau ascultarea repetată în timpul sesiunilor mai scurte.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'sk', 'Keď sú dostupné médiá, použite ich na posilnenie výslovnosti a rozpoznávania. Automatické prehrávanie je najužitočnejšie na pasívnu kontrolu alebo opakované počúvanie počas kratších relácií.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'sl', 'Ko so mediji na voljo, jih uporabite za krepitev izgovorjave in prepoznavanja. Samodejno predvajanje je najbolj uporabno za pasivno pregledovanje ali ponavljajoče se poslušanje med krajšimi sejami.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'fi', 'Kun mediaa on saatavilla, käytä sitä ääntämisen ja tunnistamisen vahvistamiseen. Automaattinen toisto on hyödyllisin passiiviseen katseluun tai toistuvaan kuunteluun lyhyempien istuntojen aikana.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'sv', 'När media är tillgänglig, använd den för att förstärka uttal och igenkänning. Autouppspelning är mest användbar för passiv granskning eller upprepad lyssning under kortare sessioner.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'tl', 'Kapag available ang media, gamitin ito upang palakasin ang pagbigkas at pagkilala. Ang autoplay ay pinakakapaki-pakinabang para sa passive na pagsusuri o paulit-ulit na pakikinig sa mas maiikling session.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'vi', 'Khi phương tiện có sẵn, hãy sử dụng nó để củng cố khả năng phát âm và nhận biết. Tự động phát hữu ích nhất cho việc xem lại thụ động hoặc nghe lặp lại trong các phiên ngắn hơn.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'tr', 'Medya mevcut olduğunda, telaffuzu ve tanınmayı güçlendirmek için bunu kullanın. Otomatik oynatma, pasif inceleme veya kısa oturumlar sırasında tekrarlanan dinleme için en kullanışlıdır.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'el', 'Όταν είναι διαθέσιμα μέσα, χρησιμοποιήστε τα για να ενισχύσετε την προφορά και την αναγνώριση. Η αυτόματη αναπαραγωγή είναι πιο χρήσιμη για παθητικό έλεγχο ή επαναλαμβανόμενη ακρόαση κατά τη διάρκεια μικρότερων περιόδων σύνδεσης.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'uk', 'Якщо медіа доступне, використовуйте його для посилення вимови та розпізнавання. Автовідтворення найбільш корисне для пасивного перегляду або повторного прослуховування під час коротших сеансів.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'ar', 'عندما تكون الوسائط متاحة، استخدمها لتعزيز النطق والتعرف. يعد التشغيل التلقائي مفيدًا جدًا للمراجعة السلبية أو الاستماع المتكرر أثناء الجلسات الأقصر.', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'hi', 'जब मीडिया उपलब्ध हो, तो उच्चारण और पहचान को सुदृढ़ करने के लिए इसका उपयोग करें। छोटे सत्रों के दौरान निष्क्रिय समीक्षा या बार-बार सुनने के लिए ऑटोप्ले सबसे उपयोगी है।', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'zh', '当有媒体可用时，用它来加强发音和识别。自动播放对于被动复习或在较短的会话期间重复聆听最有用。', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'ja', 'メディアが利用可能な場合は、それを使用して発音と認識を強化します。自動再生は、受動的なレビューや短いセッション中に繰り返し聞く場合に最も役立ちます。', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'ko', '미디어를 사용할 수 있으면 이를 사용하여 발음과 인식을 강화하십시오. 자동 재생은 짧은 세션 동안 수동적으로 복습하거나 반복적으로 듣는 데 가장 유용합니다.', CURRENT_TIMESTAMP),
